INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (44, 100101, 2, "トゥインクルウィッシュ", "ヒヨリ", "人助け、応援", 16, 155, "人助けが大好き！　前向き格闘娘", 0, "獣人族", "A", "こんにちは！　ヒヨリでっす！\n困っている人がいたら助けにいくよ！\nよかったら一緒に来ない？", "東山奈央", 8, 27);
