INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (42, 101001, 10, "自警団（カォン）", "マホ", "空想、ぬいぐるみ集め", 16, 155, "マホマホ王国のプリンセス", 0, "獣人族", "O", "マホマホ王国のお姫はんの、マホ姫どす！\nけったいな顔してどないしはったん？\nマホマホ王国はずーっと遠くの国なんどす？", "内田真礼", 9, 22);
