INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (21, 102001, 5, "リトルリリカル", "ミミ", "かわいいもの集め", 10, 117, "お歌もにんじんも、ウサギさんも大好き♪", 0, "獣人族", "O", "ぴょんぴょん、うさぎさんになりたいな～♪　\nミミ、うさぎさんになれたら、\n最初におにいちゃんに見せてあげるね！", "日高里菜", 4, 3);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (40, 102101, 9, "サレンディア救護院", "クルミ", "観劇、おままごと", 12, 150, "泣き虫で臆病な守ってあげたい女の子", 0, "ヒューマン", "B", "あの、えっと…私、く、クルミですぅ…\nふ、ふぇぇぇ…ど、どうしようぅ…\nは、恥かしくて…ご、ごめんなさいぃぃ！", "植田佳奈", 6, 9);
