INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (100, 105201, 11, "牧場（エリザベスパーク）", "リマ", "毛繕い、お喋り", 17, 150, "乙女チックなもふもふアニマル", 0, "獣人族", "A", "私、ごく普通の、どこにでもいる女の子よ！\nみ、見た目以外はね…", "徳井青空", 3, 14);
