INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (49, 108001, 12, "メルクリウス財団", "ミフユ（サマー）", "傭兵などのアルバイト", 20, 163, "仕事も私事も効率優先な傭兵少女", 0, "ヒューマン", "O", "私がキミの師匠になってあげる！\nもちろんタダとはいかないわ\n時給はしっかりもらうから", "田所あずさ", 11, 11);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (42, 108101, 7, "悪魔偽王国軍（ディアボロス）", "シノブ（ハロウィン）", "占い", 18, 157, "占いが得意な霊能少女", 0, "魔族", "AB", "私、小さい頃から人には見えないものが\n見えていたんです。今もあなたの後ろに\n一人、二人、三人…賑やかですね", "大坪由佳", 12, 22);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (32, 108201, 7, "悪魔偽王国軍（ディアボロス）", "ミヤコ（ハロウィン）", "プリンを食べること", 14, 130, "プリン大好きゴースト娘", 0, "魔族", "B", "難しいことはわからないの～\nただ毎日プリンを食べられるなら、\n幽霊のままでいいの～", "雨宮天", 1, 23);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (22, 108301, 14, "ルーセント学院", "ミサキ（ハロウィン）", "ファッション誌鑑賞、コスメ集め", 11, 120, "ちょっとおませな恋に恋する女の子", 0, "魔族", "A", "アタシのこと呼んだ？\nレディの魅力で夢中にさせてあげるわね！", "久野美咲", 1, 3);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (46, 108401, 4, "カルミナ", "チカ（クリスマス）", "各種楽器", 17, 163, "人々を守るために歌う、唱喚士の少女", 0, "ヒューマン", "O", "私は人々の平和を守るため、唱喚術を使って\n戦います。…最近は、ア、アイドルとしても\n活動してますが、そちらはまだ不慣れで…", "福原綾香", 6, 3);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (40, 108501, 9, "サレンディア救護院", "クルミ（クリスマス）", "観劇、おままごと", 12, 150, "泣き虫で臆病な守ってあげたい女の子", 0, "ヒューマン", "B", "あの、えっと…私、く、クルミですぅ…\nふ、ふぇぇぇ…ど、どうしようぅ…\nは、恥かしくて…ご、ごめんなさいぃぃ！", "植田佳奈", 6, 9);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (38, 108601, 9, "サレンディア救護院", "アヤネ（クリスマス）", "屋内でできる遊び", 14, 148, "ぷうきちといつも一緒！", 0, "ヒューマン", "B", "この子はね、ぷうきちって言うんだ\n武器なんだけど、しゃべるんだよ♪\n大事な大事な、私の友達なんだぁ～！", "芹澤優", 5, 10);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (44, 108701, 2, "トゥインクルウィッシュ", "ヒヨリ（ニューイヤー）", "人助け、応援", 16, 155, "人助けが大好き！　前向き格闘娘", 0, "獣人族", "A", "こんにちは！　ヒヨリでっす！\n困っている人がいたら助けにいくよ！\nよかったら一緒に来ない？", "東山奈央", 8, 27);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (47, 108801, 2, "トゥインクルウィッシュ", "ユイ（ニューイヤー）", "料理、人間観察", 17, 158, "戦闘のサポートが得意な、心優しい少女", 0, "ヒューマン", "O", "あんまり役に立てるかはわからないけど…\nわたしも頑張って、\nみんなをサポートするね！", "種田梨沙", 4, 5);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (46, 108901, 2, "トゥインクルウィッシュ", "レイ（ニューイヤー）", "読書、乗馬、お茶", 18, 163, "クールで何事にも真っ直ぐな剣士", 0, "魔族", "B", "キミと会ったのもきっと何かの縁だ\n一緒に塔の頂上を目指す仲間として\n頑張っていこう。よろしく頼む", "早見沙織", 1, 12);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (43, 109001, 13, "トワイライトキャラバン", "エリコ（バレンタイン）", "実験、裁縫、料理", 16, 154, "運命の相手に一途すぎる乙女", 0, "魔族", "B", "『壊し屋』の二つ名を持つ私…\nですが、怖がる必要はありませんわ\nあなた様は大切な運命の人ですから…", "橋本ちなみ", 7, 30);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (54, 109101, 3, "ラビリンス", "シズル（バレンタイン）", "家事全般", 18, 168, "お姉ちゃんがお世話してあげるからねっ！", 0, "ヒューマン", "O", "身の回りのお世話はお姉ちゃんがやってあげるね！\nお料理も、お洗濯も、お掃除も\nお風呂で背中も流してあげちゃうぞっ！", "生天目仁美", 10, 24);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (55, 109201, "", "？？？", "アン", "読書", 17, 156, "英霊と契約を結んだマナリアの天才王女", 0, "ヒューマン", "AB", "私はアン！一応、マナリア王国の\n第一王女だけど…あまりかしこまらないで、\n気軽に仲良くしてくれたら嬉しいな！", "日笠陽子", 12, 1);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (45, 109301, "", "？？？", "ルゥ", "食べること、眠ること", 16, 144, "マナリア魔法学院の新入生", 0, "ヒューマン", "O", "ルゥはルゥですぅ！マナリア魔法学院に\n通ってるですぅ。あなたもルゥの\nお友だちになってくれるですか？", "こやまきみこ", 2, 4);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (67, 109401, "", "？？？", "グレア", "ピアノ", 17, 167, "人を超越した力を有す心優しい竜姫", 0, "半人半竜", "B", "私はグレア。竜と人、両方の血を\n受け継いでいるの…\nえっと…よ、よろしくね", "福原綾香", 11, 3);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (49, 109501, 15, "ヴァイスフリューゲル　ランドソル支部", "クウカ（オーエド）", "小説を読むこと", 18, 157, "妄想大好き！　ほんとは照れ屋な女の子", 0, "ヒューマン", "AB", "あなたのことを考えていました\n…逆らえないクウカをああして、こうして\nぐふ、ぐふふふ…", "長妻樹里", 11, 19);
